export async function GET(request: NextRequest, { params }: { params: Promise<{ slug: string[] }> }) {
  return handleRequest(request, params);
}

export async function POST(request: NextRequest, { params }: { params: Promise<{ slug: string[] }> }) {
  return handleRequest(request, params);
}

export async function PUT(request: NextRequest, { params }: { params: Promise<{ slug: string[] }> }) {
  return handleRequest(request, params);
}

export async function DELETE(request: NextRequest, { params }: { params: Promise<{ slug: string[] }> }) {
  return handleRequest(request, params);
}

async function handleRequest(request: NextRequest, paramsPromise: Promise<{ slug: string[] }>) {
  const { slug } = await paramsPromise;
  const slugStr = slug.join("/");
  const ep = ENDPOINTS[slugStr];

  if (!ep) {
    return NextResponse.json({ error: "Endpoint not found", slug: slugStr }, { status: 404 });
  }

  // Free APIs
  if (ep.free && ep.base) {
    return proxyToFreeAPI(request, ep.base, ep.path, ep.method || "GET");
  }

  // RapidAPI endpoints
  return proxyToRapidAPI(request, ep.host, ep.path, ep.method || "POST");
}
